// ============================================================================
// TENSTORRENT PER-CHIP VRAM MODEL  (replaces the flat aggregate "fits if total <= sum(chip GB)" check)
// Default precision profile = DecodersPrecision.performance (the realistic vLLM serving default).
// All sizes in BYTES unless noted. GiB = 2^30.
// ============================================================================

// ---- 0. INPUTS ----
// model: paramsTotalB, hiddenSize, attention{numLayers, numKvHeads, headDim, kind...}, moe, intermediateSize, ffnGated(bool), vocabSize
// hardware (TT SKU): arch in {WH, BH}, numChips, meshShape=[rows,cols] (e.g. N150=[1,1], N300=[1,2], T3K=[1,8], Galaxy=[8,4]), ttDataParallel
// model_spec entry (per model+device): maxModelLen, maxNumSeqs (=batch S), blockSize (=64), traceRegionBytes (0 if absent), maxTokensAllUsersOverride?
// precisionProfile in {performance(default), accuracy}; perTensorBpw map derived below

// ---- 1. EFFECTIVE WEIGHT BYTES-PER-PARAM (mixed block-float) ----
// Block-float byte costs (DERIVED from 16-elem shared-exponent tile, NOT a source constant but standard):
const BPW = { BFP4: 0.5625 /* 9/16 */, BFP8: 1.0625 /* 17/16 */, BF16: 2.0 };
// performance profile per TensorGroup (default): FF1_FF3=BFP4; FF2=BFP8; WQKV=BFP8; WO=BFP8; KV_CACHE=BFP8
// (per-model exceptions: Qwen2.5-7B/VL-7B -> WQKV/WO/KV=BF16, FFN stays BFP8 (no BFP4); GPT-OSS -> experts MXFP4 ~0.55, attn bf16/bfp8)
// Compute the per-decoder weight param split FROM MODEL DIMS (source does not store s_* constants):
//   d_q   = numAttnHeads * headDim;   d_kv = numKvHeads * headDim
//   attnParamsPerLayer = hidden*(d_q + 2*d_kv)  [WQKV]  +  hidden*hidden [WO]
//   ffnParamsPerLayer  = (ffnGated ? 3 : 2) * hidden * intermediateSize   // dense; MoE: * numExperts (ALL experts resident)
//   f_attn = attnParamsPerLayer / (attnParamsPerLayer + ffnParamsPerLayer);  f_ffn = 1 - f_attn
//   within attn: s_qkv = (d_q+2*d_kv)/(d_q+2*d_kv + hidden); s_wo = 1 - s_qkv
//   within ffn (SwiGLU/gated): s_13 = 2/3, s_2 = 1/3;  (non-gated): s_13 = 1/2, s_2 = 1/2
// effective_bpw applies ONLY to the in-decoder weights; embeddings/lm_head/norms ride at their own dtype (treat as BF16 default unless quantized):
effective_bpw_decoder =
    f_attn * ( s_qkv*BPW[WQKV] + s_wo*BPW[WO] )
  + f_ffn  * ( s_13 *BPW[FF1_FF3] + s_2*BPW[FF2] );
// For MoE the experts dominate (f_ffn>0.9) so effective_bpw ~= s_13*BFP4 + s_2*BFP8 ~= 0.73 B/param.
// For dense (Llama/Qwen8B) f_ffn~0.75-0.80 -> effective_bpw ~= 0.8-0.9 B/param.

// total weight bytes (whole model). If you keep a single global quant slider, override per-tensor BPW with that quant.
weights_total_bytes = paramsTotalB * 1e9 * effective_bpw_decoder;   // decoder weights
// (optional refinement: split out embedding+lmHead params at BF16; small for big models, ~few % for tiny ones)

// ---- 2. KV CACHE BYTES (FIXED TOKEN BUDGET, BFP8) ----
const KV_BPE = 1.0625;            // ttnn.bfloat8_b default (1 mantissa byte/elem + 1 shared-exp byte / 16 elems)
const BLOCK_SIZE = 64;            // operative paged-attn page (model_spec block_size="64"; LOW-confidence as a hard source constant)
S = maxNumSeqs;                   // vLLM --max-num-seqs (batch)
T = maxTokensAllUsersOverride ?? min(maxModelLen, FALLBACK=131072);  // FIXED budget, NOT user context (see resolution table in dataFields)
// per-user worst-case padding (worker.py): one extra block_size per concurrent user
num_blocks = ceil( (T + BLOCK_SIZE * S) / BLOCK_SIZE );
// per-layer KV tensor shape = (num_blocks, kv_heads_per_dev, BLOCK_SIZE, headDim), x2 for K and V.
// KV is pre-sliced by n_local_kv_heads then ReplicateTensorToMesh, so per-chip holds only its head slice:
ND = numChips / ttDataParallel;                              // devices per DP submesh
kv_heads_per_dev = numKvHeads / min(ND, numKvHeads);         // TP head sharding; floors at 1 KV head
kv_bytes_per_chip = num_blocks * kv_heads_per_dev * BLOCK_SIZE * headDim * KV_BPE * numLayers * 2;
// NOTE for non-GQA-uniform architectures (MLA/SWA/hybrid/compressed): keep the calculator's existing per-arch
//   per-token-per-layer element count, but (a) substitute KV_BPE=1.0625, (b) size to T tokens (rounded to num_blocks*BLOCK_SIZE)
//   instead of contextLength, (c) divide the head/KV dimension by min(ND, kvHeadEquivalent). The token-budget and BFP8
//   substitutions are the TT-specific corrections; the per-arch geometry is unchanged.

// ---- 3. PER-CHIP WEIGHT SHARDING (replicated norm fraction) ----
// Everything sharded EXCEPT RMSNorm/LayerNorm weights (ReplicateTensorToMesh) -> on EVERY chip.
const REPLICATED_WEIGHT_FRACTION_TT = 0.005;   // norms only; ~0.3-0.8% of params. Use 0.005 (was 0.03 generic - too high for TT).
r = (numChips > 1) ? REPLICATED_WEIGHT_FRACTION_TT : 0;
weights_per_chip = weights_total_bytes * ( (1 - r)/numChips + r );
// (Galaxy 8x4: weights are 2D-sharded across rows*cols=32, embeddings/norms replicate across the 8 rows;
//  the (1-r)/numChips term already captures the dominant /32 split; r covers the replicated norms.)

// ---- 4. ACTIVATIONS / PREFILL WORKSPACE (DRAM, per chip) ----
// Decode activations live in L1 SRAM (NOT DRAM) -> ~0 to DRAM budget.
// Prefill activations live in DRAM, bounded by chunk_tokens (NOT full seq_len):
chunk_tokens = min(maxModelLen, max_prefill_chunk_size);     // max_prefill_chunk_size = div1024_entry*1024 (default 4096); per (model,device) table
k = 3;  // ~2-4 live tensors (residual + MLP intermediate + transient SDPA); INFERRED, not a source constant
act_bpe = 2;  // bf16 worst case (QKV path); SDPA/wo path is bf8_b=1 -> this is an upper bound
prefill_act_per_chip = k * chunk_tokens * max(hiddenSize, intermediateSize) * act_bpe / max(1, ND);
// This is tens-to-low-hundreds of MB; dwarfed by weights+KV. Treat as a per-chip workspace add, sharded by ND.

// ---- 5. USABLE DRAM PER CHIP (allocator-accurate) ----
// usable_per_bank = dram_view_size - dram_unreserved_base - align(traceRegionBytes, dram_alignment)
// WH: num_views=12, dram_view_size=1073741824, unreserved_base=1048640, align=32
// BH: num_views=8,  dram_view_size=4278190080, unreserved_base=1048704, align=64
usable_dram_per_chip = num_views * ( dram_view_size - dram_unreserved_base - alignUp(traceRegionBytes, dram_alignment) );
//   WH trace=0 -> 12 * (1073741824 - 1048640)        = 12,872,318,208 B = 11.988 GiB
//   BH trace=0 -> 8  * (4278190080 - 1048704)         = 34,217,131,008 B = 31.867 GiB
// trace is subtracted from EVERY bank: total trace cost = align(traceRegionBytes)*num_views.
// (optional +256 MiB/bank only if TT_METAL_DRAM_BACKED_CQ=1; default OFF -> omit.)

// ---- 6. FIT CHECK (per chip is the binding constraint) ----
per_chip_required = weights_per_chip + kv_bytes_per_chip + prefill_act_per_chip;   // bytes
utilization = per_chip_required / usable_dram_per_chip;
verdict = utilization > 1 ? 'wont-fit' : utilization > 0.9 ? 'tight' : 'fits';
// Aggregate view (for the UI bar) = per_chip_required * numChips, usable = usable_dram_per_chip * numChips.
// The VERDICT must come from the PER-CHIP ratio, never the aggregate ratio.
